  ('unmasked', 'B', 3, '{"fr": "T''as déjà pleuré pendant ou après l''amour ?", "en": "Ever cried during or after sex?", "es": "¿Has llorado durante o después del sexo?", "de": "Hast du beim oder nach dem Sex geweint?"}', '[{"tag":"romantique","points":2},{"tag":"empathique","points":2}]'),
  ('unmasked', 'C', 3, '{"fr": "Si tu mourais ce soir, ton plus grand regret ?", "en": "If you died tonight, your biggest regret?", "es": "Si murieras esta noche, ¿tu mayor arrepentimiento?", "de": "Wenn du heute Nacht stirbst, dein größtes Bedauern?"}', '[{"tag":"empathique","points":3}]'),
  ('unmasked', 'B', 2, '{"fr": "T''as déjà poignardé quelqu''un dans le dos ?", "en": "Ever stabbed someone in the back?", "es": "¿Has apuñalado a alguien por la espalda?", "de": "Hast du jemanden hintergangen?"}', '[{"tag":"fiable","points":-3},{"tag":"audacieux","points":1}]'),
  ('unmasked', 'B', 2, '{"fr": "T''as déjà prétendu être quelqu''un d''autre en ligne ?", "en": "Ever pretended to be someone else online?", "es": "¿Has fingido ser otra persona online?", "de": "Hast du dich online als jemand anderes ausgegeben?"}', '[{"tag":"mysterieux","points":2},{"tag":"audacieux","points":1}]');
